SELECT id, user_id, application_status, submitted_at, exam_duration, answers, admin_remarks, reviewed_at
FROM certification_application
WHERE id = #{id}

SELECT id, user_id, application_status, submitted_at, exam_duration, answers, admin_remarks, reviewed_at
FROM certification_application
WHERE user_id = #{userId}

SELECT id, user_id, application_status, submitted_at, exam_duration, answers, admin_remarks, reviewed_at
FROM certification_application
WHERE application_status = #{status}

SELECT id, user_id, application_status, submitted_at, exam_duration, answers, admin_remarks, reviewed_at
FROM certification_application
WHERE user_id = #{userId} AND application_status = #{status}
